refsection.programlisting:
// Create example data
data = [1 2 3; 4 5 6; 7 8 9];
test_file = TMPDIR + "/test_write.xlsx";

// Write numeric matrix to default sheet starting at A1
xlsxWrite(data, test_file);

// Write to specific sheet by name
xlsxWrite(data, test_file, "sheet", "Sheet1");

// Write to specific sheet by index (must exist)
xlsxWrite(data, test_file, "sheet", 1);

// Write starting at specific position
xlsxWrite(data, test_file, "range", "B5");

// Write using matrix range notation [row col]
xlsxWrite(data, test_file, "range", [5 2; 13 4]);  // B5:D13

// Clear sheet before writing (overwrite mode)
xlsxWrite(data, test_file, "sheet", 1, "writemode", "overwrite");

// Append data preserving existing content
xlsxWrite(data, test_file, "sheet", 1, "writemode", "append", "range", "A10");

// Write with document metadata
xlsxWrite(data, test_file, "title", "My Report", "subject", "Data Analysis", ..
          "description", "Quarterly analysis results");

// Write string matrix
text_data = ["Name" "Age" "City"; "Alice" "25" "Paris"; "Bob" "30" "London"];
people_file = TMPDIR + "/people.xlsx";
xlsxWrite(text_data, people_file, "sheet", 1);

// Write cell
c = {1, "A"; 2, "B"; 3, "C"}
cell_file = TMPDIR + "/cell_data.xlsx";
xlsxWrite(c, cell_file);

// Complete example combining all options
report_file = TMPDIR + "/report.xlsx";
xlsxWrite(data, report_file, "sheet", 1, "range", "B2", ..
          "writemode", "overwrite", "title", "Q1 Report", ..
          "subject", "Sales Data", "description", "First quarter sales figures");

ret = xlsxRead(report_file)
